; ***************************************************************************************
; Tube address/data dispatch
; 
; Called by 10 sites across the Tube host and Econet
; code. Routes requests based on the value of A:
;   A < &80: data transfer setup (SENDW) at &0435
;   &80 <= A < &C0: release -- maps A via ORA #&40
;     and compares with tube_claimed_id; if we own
;     this address, falls through to tube_release_claim
;   A >= &C0: external address claim from another host
; Falls through to tube_release_claim when releasing our
; current claim.
; 
; On Entry:
;     A: request type (<&80 data, &80-&BF release, &C0+ claim)
;     X: transfer address low (data transfer only)
;     Y: transfer address high (data transfer only)
; ***************************************************************************************
; &bf0a referenced 10 times by &0493[2], &04cb[2], &837c, &844f, &8933, &893b, &9ff2, &a009, &a075, &a2ec
.tube_addr_data_dispatch
    cmp #&80                                                          ; bf0a: c9 80       ..  :0406[2]   ; A>=&80: address claim; A<&80: data transfer
    bcc tube_transfer_setup                                           ; bf0c: 90 2b       .+  :0408[2]   ; A<&80: data transfer setup (SENDW)
    cmp #&c0                                                          ; bf0e: c9 c0       ..  :040a[2]   ; A>=&C0: new address claim from another host
    bcs addr_claim_external                                           ; bf10: b0 1a       ..  :040c[2]   ; C=1: external claim, check ownership
    ora #&40 ; '@'                                                    ; bf12: 09 40       .@  :040e[2]   ; Map &80-&BF range to &C0-&FF for comparison
    cmp tube_claimed_id                                               ; bf14: c5 15       ..  :0410[2]   ; Is this for our currently-claimed address?
    bne return_tube_init                                              ; bf16: d0 20       .   :0412[2]   ; Not our address: return
; ***************************************************************************************
; Release Tube address claim via R4 command 5
; 
; Saves interrupt state (PHP/SEI) to protect the R4
; protocol sequence, sends R4 command 5 (release) followed
; by the currently-claimed address from tube_claimed_id
; (&15), then restores interrupts (PLP). Falls through to
; clear_tube_claim to reset the claimed-address state to
; the &80 sentinel.
; ***************************************************************************************
; &bf18 referenced 1 time by &0471[2]
.tube_release_claim
    php                                                               ; bf18: 08          .   :0414[2]   ; PHP: save interrupt state for release
    sei                                                               ; bf19: 78          x   :0415[2]   ; SEI: disable interrupts during R4 protocol
    lda #5                                                            ; bf1a: a9 05       ..  :0416[2]   ; R4 cmd 5: release our address claim
    jsr tube_send_r4                                                  ; bf1c: 20 9e 06     .. :0418[2]   ; Send release command to co-processor
    lda tube_claimed_id                                               ; bf1f: a5 15       ..  :041b[2]   ; Load our currently-claimed address
    jsr tube_send_r4                                                  ; bf21: 20 9e 06     .. :041d[2]   ; Send our address as release parameter
    plp                                                               ; bf24: 28          (   :0420[2]   ; Restore interrupt state
; ***************************************************************************************
; Reset Tube address claim state
; 
; Stores &80 into both tube_claimed_id (&15) and
; tube_claim_flag (&14). The &80 sentinel indicates no
; address is currently claimed and no claim is in
; progress. Called after tube_release_claim (via
; fall-through) and during initial workspace setup.
; ***************************************************************************************
; &bf25 referenced 1 time by &beb3
.clear_tube_claim
