    sta tube_claimed_id                                               ; bf27: 85 15       ..  :0423[2]   ; &80 sentinel = no address currently claimed
    sta tube_claim_flag                                               ; bf29: 85 14       ..  :0425[2]   ; Store to claim-in-progress flag
    rts                                                               ; bf2b: 60          `   :0427[2]   ; Return from tube_post_init

; &bf2c referenced 1 time by &040c[2]
