    cmp tube_claimed_id                                               ; bf30: c5 15       ..  :042c[2]   ; Compare with our claimed address
    beq return_tube_init                                              ; bf32: f0 04       ..  :042e[2]   ; Match: return (we already have it)
    clc                                                               ; bf34: 18          .   :0430[2]   ; Not ours: CLC = we don't own this address
    rts                                                               ; bf35: 60          `   :0431[2]   ; Return with C=0 (claim denied)

