; Protection attribute keyword table. Each entry:
; ASCII name + flag byte (&80+) + OR mask + AND mask.
; Used by *Prot (ORA lo byte) and *Unprot (AND hi
; byte) to set/clear individual protection bits.
; Also listed by *HELP Prot/*HELP Unprot via the
; shared commands handler (syntax index 14).
; Bits: 0=Peek 1=Poke 2=JSR 3=Proc 4=Utils 5=Halt
.cmd_table_copro
    equs "Halt"                                                       ; a4c3: 48 61 6c... Hal            ; Halt
    equb &fc                                                          ; a4c7: fc          .              ; Flag &FC: V no arg, syn 28 (unused)
    equb &20                                                          ; a4c8: 20                         ; *Prot OR mask: bit 5
    equb &df                                                          ; a4c9: df          .              ; *Unprot AND mask: ~bit 5
    equs "JSR"                                                        ; a4ca: 4a 53 52    JSR            ; JSR
    equb &fc                                                          ; a4cd: fc          .              ; Flag &FC: V no arg, syn 28 (unused)
    equb 4                                                            ; a4ce: 04          .              ; *Prot OR mask: bit 2
    equb &fb                                                          ; a4cf: fb          .              ; *Unprot AND mask: ~bit 2
    equs "Peek"                                                       ; a4d0: 50 65 65... Pee            ; Peek
    equb &fc                                                          ; a4d4: fc          .              ; Flag &FC: V no arg, syn 28 (unused)
    equb 1                                                            ; a4d5: 01          .              ; *Prot OR mask: bit 0
    equb &fe                                                          ; a4d6: fe          .              ; *Unprot AND mask: ~bit 0
    equs "Poke"                                                       ; a4d7: 50 6f 6b... Pok            ; Poke
    equb &fc                                                          ; a4db: fc          .              ; Flag &FC: V no arg, syn 28 (unused)
    equb 2                                                            ; a4dc: 02          .              ; *Prot OR mask: bit 1
    equb &fd                                                          ; a4dd: fd          .              ; *Unprot AND mask: ~bit 1
    equs "Proc"                                                       ; a4de: 50 72 6f... Pro            ; Proc
    equb &fc                                                          ; a4e2: fc          .              ; Flag &FC: V no arg, syn 28 (unused)
    equb 8                                                            ; a4e3: 08          .              ; *Prot OR mask: bit 3
    equb &f7                                                          ; a4e4: f7          .              ; *Unprot AND mask: ~bit 3
    equs "Utils"                                                      ; a4e5: 55 74 69... Uti            ; Utils
    equb &a9                                                          ; a4ea: a9          .              ; Flag &A9: syn 9 (unused)
    equb &10                                                          ; a4eb: 10          .              ; *Prot OR mask: bit 4
    equb &ef                                                          ; a4ec: ef          .              ; *Unprot AND mask: ~bit 4
    equb &80                                                          ; a4ed: 80          .              ; End of attribute keyword table

; ***************************************************************************************
; Filing system OSWORD entry
; 
; Handles MOS service call 8 (unrecognised OSWORD).
; Filters OSWORD codes &0E-&14 by subtracting &0E (via
; CLC/SBC &0D) and rejecting values outside 0-6. For
; valid codes, calls osword_setup_handler to push the
; dispatch address, then copies 3 bytes from the RX
; buffer to osword_flag workspace.
; ***************************************************************************************
.svc_8_osword
    clc                                                               ; a4ee: 18          .              ; CLC so SBC subtracts value+1
    lda osbyte_a_copy                                                 ; a4ef: a5 ef       ..             ; A = OSWORD number
    sbc #&0d                                                          ; a4f1: e9 0d       ..             ; A = OSWORD - &0E (CLC+SBC = -&0E)
    bmi return_from_osword_setup                                      ; a4f3: 30 2d       0-             ; Below &0E: not ours, return
    cmp #7                                                            ; a4f5: c9 07       ..             ; Index >= 7? (OSWORD > &14)
    bcs return_from_osword_setup                                      ; a4f7: b0 29       .)             ; Above &14: not ours, return
    tax                                                               ; a4f9: aa          .              ; X=OSWORD handler index (0-6)
    ldy #6                                                            ; a4fa: a0 06       ..             ; Y=6: save 6 workspace bytes
; &a4fc referenced 1 time by &a507
.loop_ca4fc
    lda svc_state,y                                                   ; a4fc: b9 a9 00    ...            ; Load current workspace byte
    pha                                                               ; a4ff: 48          H              ; Save on stack
    lda l00ed,y                                                       ; a500: b9 ed 00    ...            ; Load OSWORD parameter byte
    sta svc_state,y                                                   ; a503: 99 a9 00    ...            ; Copy parameter to workspace
    dey                                                               ; a506: 88          .              ; Next byte down
    bne loop_ca4fc                                                    ; a507: d0 f3       ..             ; Loop for all 6 bytes
    jsr osword_setup_handler                                          ; a509: 20 16 a5     ..            ; Set up dispatch and save state
    ldy #&fa                                                          ; a50c: a0 fa       ..             ; Y=&FA: restore 6 workspace bytes
; &a50e referenced 1 time by &a513
.loop_ca50e
    pla                                                               ; a50e: 68          h              ; Restore saved workspace byte
    sta lffb0,y                                                       ; a50f: 99 b0 ff    ...            ; Store to osword_flag workspace
    iny                                                               ; a512: c8          .              ; Next byte
    bne loop_ca50e                                                    ; a513: d0 f9       ..             ; Loop until all 6 restored
    rts                                                               ; a515: 60          `              ; Return from svc_8_osword

; ***************************************************************************************
; Push OSWORD handler address for RTS dispatch
; 
; Indexes the OSWORD dispatch table by X to
; push a handler address (hi then lo) onto the
; stack. Copies 3 bytes from the osword_flag
; workspace into the RX buffer, loads PB byte 0
; (the OSWORD sub-code), and clears svc_state.
; The subsequent RTS dispatches to the pushed
; handler address.
; 
; On Entry:
;     X: OSWORD handler index (0-6)
; ***************************************************************************************
; &a516 referenced 1 time by &a509
.osword_setup_handler
    lda osword_dispatch_hi_table,x                                    ; a516: bd 2a a5    .*.            ; X = OSWORD index (0-6); Load handler address high byte
    pha                                                               ; a519: 48          H              ; Push high byte for RTS dispatch
    lda osword_dispatch_lo_table,x                                    ; a51a: bd 23 a5    .#.            ; Load handler address low byte
    pha                                                               ; a51d: 48          H              ; Push low byte for RTS dispatch
    lda (ws_ptr_hi),y                                                 ; a51e: b1 ac       ..             ; Copy 3 bytes (Y=2,1,0); Load PB byte 0 (OSWORD sub-code)
    sty svc_state                                                     ; a520: 84 a9       ..             ; Load from osword_flag workspace; Clear service state
; &a522 referenced 2 times by &a4f3, &a4f7
.return_from_osword_setup
    rts                                                               ; a522: 60          `              ; RTS dispatches to pushed handler

; OSWORD dispatch table (7 entries, split lo/hi).
; PHA/PHA/RTS dispatch used by svc_8_osword.
; Maps OSWORD codes &0E-&14 to handler routines.
; &a523 referenced 1 time by &a51a
.osword_dispatch_lo_table
    equb <(osword_0e_handler-1)                                       ; a523: 30          0              ; lo-&0E: Read clock; lo-&13: Misc operations; Store to RX buffer
    equb <(return_from_osword_setup-1)                                ; a524: 21          !
    equb <(osword_10_handler-1)                                       ; a525: a3          .
    equb <(osword_11_handler-1)                                       ; a526: c0          .
    equb <(osword_12_handler-1)                                       ; a527: 18          .
    equb <(osword_13_dispatch-1)                                      ; a528: 2d          -
    equb <(osword_14_handler-1)                                       ; a529: c4          .
; &a52a referenced 1 time by &a516
.osword_dispatch_hi_table
    equb >(osword_0e_handler-1)                                       ; a52a: a5          .
    equb >(return_from_osword_setup-1)                                ; a52b: a5          .              ; hi-&0E: Read clock
    equb >(osword_10_handler-1)                                       ; a52c: a5          .              ; hi-&0F: (unimplemented)
    equb >(osword_11_handler-1)                                       ; a52d: a5          .              ; hi-&10: Transmit
    equb >(osword_12_handler-1)                                       ; a52e: a6          .
    equb >(osword_13_dispatch-1)                                      ; a52f: a6          .              ; hi-&12: Read station info
    equb >(osword_14_handler-1)                                       ; a530: a8          .

