; ***************************************************************************************
; Convert binary byte to BCD
; 
; Uses decimal mode (SED) with a count-up loop:
; starts at BCD 0 and adds 1 in decimal mode for
; each decrement of the binary input. Saves and
; restores the processor flags to avoid leaving
; decimal mode active. Called 6 times by
; save_txcb_and_convert for clock date/time
; conversion.
; 
; On Entry:
;     A: binary value (0-99)
; 
; On Exit:
;     A: BCD equivalent
; ***************************************************************************************
; &a595 referenced 6 times by &a549, &a552, &a55b, &a56d, &a577, &a584
.bin_to_bcd
    php                                                               ; a595: 08          .              ; Save processor flags (decimal mode)
    tax                                                               ; a596: aa          .              ; X = binary count
    beq done_bcd_convert                                              ; a597: f0 09       ..             ; Zero: result is 0, skip loop
    sed                                                               ; a599: f8          .              ; Set decimal mode for BCD add
    lda #0                                                            ; a59a: a9 00       ..             ; Start BCD result at 0
; &a59c referenced 1 time by &a5a0
.loop_bcd_add
    clc                                                               ; a59c: 18          .              ; Clear carry for BCD add
    adc #1                                                            ; a59d: 69 01       i.             ; Add 1 in decimal mode
    dex                                                               ; a59f: ca          .              ; Count down binary value
    bne loop_bcd_add                                                  ; a5a0: d0 fa       ..             ; Loop until zero
; &a5a2 referenced 1 time by &a597
.done_bcd_convert
    plp                                                               ; a5a2: 28          (              ; Restore flags (clears decimal mode)
    rts                                                               ; a5a3: 60          `              ; Return with BCD result in A

